gizmo:
await clear();

const gizmo = OBJ();

const x = gizmo.segment();
await x.offset(4, 0, 0);
await x.color(FULL);

// Reset to origin
const rs1 = gizmo.segment();
await rs1.offset(0, 0, 0);
await rs1.absolute(true);
await rs1.color(INVISIBLE);

const y = gizmo.segment();
await y.offset(0, 4, 0);
await y.color(DIM);

// Reset to origin
const rs2 = gizmo.segment();
await rs2.offset(0, 0, 0);
await rs2.absolute(true);
await rs2.color(INVISIBLE);

const z = gizmo.segment();
await z.offset(0, 0, 4);
await z.color(DARK);

cube:
await clear();

// Cube with one corner being a gizmo
const cube = OBJ();

const length = 4;

let leg;

// Center square
leg = cube.segment();
await leg.offset(-length / 2, -length / 2, -length / 2);
await leg.color(INVISIBLE);

// Lower square
leg = cube.segment();
await leg.offset(length, 0, 0);
await leg.color(FULL);
leg = cube.segment();
await leg.offset(0, length, 0);
leg = cube.segment();
await leg.offset(-length, 0, 0);
leg = cube.segment();
await leg.offset(0, -length, 0);
await leg.color(DIM);

// Transport to upper square
leg = cube.segment();
await leg.offset(0, 0, length);
await leg.color(DARK);

// Upper square
leg = cube.segment();
await leg.offset(length, 0, 0);
leg = cube.segment();
await leg.offset(0, length, 0);
leg = cube.segment();
await leg.offset(-length, 0, 0);
leg = cube.segment();
await leg.offset(0, -length, 0);

// Final vertical legs
leg = cube.segment();
await leg.offset(length, 0, -length);
await leg.color(INVISIBLE);

leg = cube.segment();
await leg.offset(0, 0, length);

leg = cube.segment();
await leg.offset(0, length, -length);
await leg.color(INVISIBLE);

leg = cube.segment();
await leg.offset(0, 0, length);

leg = cube.segment();
await leg.offset(-length, 0, -length);
await leg.color(INVISIBLE);

leg = cube.segment();
await leg.offset(0, 0, length);

// Spin cube about x axis
while (true) {
    const t = performance.now() / 1000;

    const dir = VEC(0, Math.cos(t), Math.sin(t));
    const up = VEC(1, 0, 0);

    const quat = QUAT.fromDirection(dir, up);
    cube.pivot(quat);

    await sleep(100);
}

arrow:
await clear();

let seg;

// The original arrow
const shaft = OBJ();

// Main shaft
seg = shaft.segment();
await seg.offset(7, 0, 0);

seg = shaft.segment();
await seg.offset(0, 2, 1);
await seg.color(INVISIBLE);

// Approximate a circle
const corners = [
    [1, 2],
    [2, 1],
    [2, -1],
    [1, -2],
    [-1, -2],
    [-2, -1],
    [-2, 1],
    [-1, 2],
    [1, 2],
];

for (let i = 1; i < corners.length; i++) {
    const [lZ, lY] = corners[i - 1];
    const [cZ, cY] = corners[i];

    seg = shaft.segment();
    await seg.offset(0, cY - lY, cZ - lZ);
}

const fletching = OBJ();
await fletching.parent(shaft);

const feathers = [
    [-1, -1],
    [-1, 1],
    [1, -1],
    [1, 1],
];

for (const [i, [y, z]] of feathers.entries()) {
    if (i !== 0) {
        // Reset to 0
        seg = fletching.segment();
        await seg.absolute(true);
    }

    seg = fletching.segment();
    await seg.offset(-1, y, z);
    await seg.absolute(true);
    await seg.color(DIM);
}

const head = OBJ();
await head.parent(shaft);
await head.pos(7, 0, 0);
await head.rlock(true, false);

// Initial positioning move
seg = head.segment();
await seg.offset(0, 2, 0);
await seg.color(INVISIBLE);

seg = head.segment();
await seg.offset(4, -2, 0);

seg = head.segment();
await seg.offset(-4, -2, 0);

// Rotate arrow
while (true) {
    const t = performance.now() / 5000;

    // Rotate arrow
    const dir = VEC(Math.cos(t), 0, Math.sin(t));
    const up = VEC(0, 1, 0);

    const quat = QUAT.fromDirection(dir, up);

    // Change arrow inclination
    const incDir = VEC(
        0,
        5,
        Math.sign(Math.sin(t)) * Math.abs(Math.sin(2 * t)),
    );
    const incUp = VEC(1, 0, 0);

    quat.rotateBy(QUAT.fromDirection(incDir, incUp));
    quat.rotateBy(QUAT(Math.sin(Math.PI / 4), 0, 0, Math.cos(Math.PI / 4)));

    shaft.pivot(quat);

    // Hide head if angle too extreme
    head.visible(Math.abs(VEC(0, 0, 1).dot(dir)) < 0.7);

    // Hide cross if pointing away and very extreme angle
    fletching.visible(VEC(0, 0, 1).dot(dir) <= 0.9);

    await sleep(100);
}

helix:
await clear();

// Number of objects to render
const OBJ_CT = 4;

const radius = 5;
const helixA = OBJ();

// Using ALL available objects + segments

let seg;

// Initial positioning
seg = helixA.segment();
await seg.offset(0, radius, 0);
await seg.color(INVISIBLE);

const helixB = OBJ_CT > 1 ? OBJ() : null;
helixB?.parent(helixA);
helixB?.pos(15, 0, 0);

// Initial positioning
seg = helixB?.segment();
await seg?.offset(0, radius, 0);
await seg?.color(INVISIBLE);

const helixC = OBJ_CT > 2 ? OBJ() : null;
helixC?.parent(helixA);
helixC?.pos(2, 0, 0);

// Initial positioning
seg = helixC?.segment();
await seg?.offset(0, radius, 0);
await seg?.color(INVISIBLE);

const helixD = OBJ_CT > 3 ? OBJ() : null;
helixD?.parent(helixA);
helixD?.pos(17, 0, 0);

// Initial positioning
seg = helixD?.segment();
await seg?.offset(0, radius, 0);
await seg?.color(INVISIBLE);

const step = (2 * Math.PI) / 15;

for (let i = 1; i < 16; i++) {
    const lx = i - 1;
    const ly = Math.cos((i - 1) * step) * radius;
    const lz = Math.sin((i - 1) * step) * radius;

    const cx = i;
    const cy = Math.cos(i * step) * radius;
    const cz = Math.sin(i * step) * radius;

    seg = helixA.segment();
    await seg.offset(cx - lx, cy - ly, cz - lz);

    if (OBJ_CT > 1) {
        seg = helixB?.segment();
        await seg?.offset(cx - lx, cy - ly, cz - lz);
    }

    if (OBJ_CT > 2) {
        seg = helixC?.segment();
        seg?.offset(cx - lx, cy - ly, cz - lz);
        await seg?.color(DIM);
    }

    if (OBJ_CT > 3) {
        seg = helixD?.segment();
        seg?.offset(cx - lx, cy - ly, cz - lz);
        await seg?.color(DIM);
    }
}

// Rotate helix
while (true) {
    const t = performance.now() / 2000;

    const quat = QUAT(Math.sin(t / 2), 0, 0, Math.cos(t / 2));

    await helixA.pivot(quat);
}
